import { useMemo } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";
import InfoTooltip from "../../components/InfoTooltip";

/* ── regime constants ────────────────────────────────── */
const REGIMES = {
  TRENDING:       { color: "var(--v2-green)",  bg: "rgba(110,240,180,0.15)", label: "Trending",
    description: "Market is directionally trending — prices move persistently in one direction. Momentum and breakout strategies perform best. Characterized by higher highs/lows (uptrend) or lower highs/lows (downtrend)." },
  MEAN_REVERTING: { color: "var(--v2-blue)",   bg: "rgba(150,190,255,0.15)", label: "Mean-Reverting",
    description: "Market oscillates around a central value — prices that deviate tend to snap back. Range-bound and pullback strategies excel. Bollinger Bands and RSI mean-reversion signals are most reliable." },
  HIGH_VOL:       { color: "var(--v2-red)",    bg: "rgba(255,120,120,0.15)", label: "High Volatility",
    description: "Market experiences large, unpredictable swings — VIX is elevated, news-driven moves dominate. Risk management is critical: tighter stops, smaller position sizes. Many strategies underperform." },
};

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── map API regime names to our constant keys ────────── */
const REGIME_MAP = {
  trending_up: "TRENDING", trending_down: "TRENDING",
  mean_reverting: "MEAN_REVERTING", high_volatility: "HIGH_VOL",
  TRENDING: "TRENDING", MEAN_REVERTING: "MEAN_REVERTING", HIGH_VOL: "HIGH_VOL",
};

/* ── main page ───────────────────────────────────────── */
export default function Regimes() {
  const { state } = useAppStore();

  /* poll the v2 regime classification endpoint */
  const { data: regimeData, loading: loadingBt } = usePoll(
    async () => { const r = await http.get("/v2/regimes"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* derive regime state from API response */
  const rawRegime = regimeData?.current_regime ?? null;
  const currentRegime = rawRegime ? (REGIME_MAP[rawRegime] || null) : null;
  const confidence = regimeData?.confidence != null ? Math.round(regimeData.confidence * 100) : null;

  /* compute duration from historical data */
  const duration = useMemo(() => {
    if (!regimeData?.historical || regimeData.historical.length === 0) return null;
    const lastEnded = regimeData.historical[regimeData.historical.length - 1]?.ended;
    if (!lastEnded) return null;
    const daysSince = Math.round((Date.now() / 1000 - lastEnded) / 86400);
    return daysSince > 0 ? daysSince : 1;
  }, [regimeData]);

  const totalTransitions = regimeData?.historical?.length ?? null;

  /* build timeline from historical entries */
  const timeline = useMemo(() => {
    if (!regimeData?.historical || regimeData.historical.length === 0) return [];
    const entries = [...regimeData.historical];
    const result = [];
    for (let i = 0; i < entries.length; i++) {
      const name = REGIME_MAP[entries[i].name] || "MEAN_REVERTING";
      const ended = entries[i].ended || (Date.now() / 1000);
      const started = i > 0 ? (entries[i - 1].ended || 0) : (ended - 30 * 86400);
      const days = Math.max(1, Math.round((ended - started) / 86400));
      result.push({ regime: name, days });
    }
    /* add current regime segment */
    if (currentRegime && entries.length > 0) {
      const lastEnded = entries[entries.length - 1].ended || (Date.now() / 1000);
      const days = Math.max(1, Math.round((Date.now() / 1000 - lastEnded) / 86400));
      result.push({ regime: currentRegime, days });
    }
    return result;
  }, [regimeData, currentRegime]);
  const totalDays = timeline.reduce((a, b) => a + (b.days || 0), 0);

  /* build transition matrix placeholder from probabilities */
  const transitions = useMemo(() => {
    if (!regimeData?.probabilities) return {};
    /* build a simple placeholder matrix from regime data */
    const regimes = (regimeData.regimes || []);
    if (regimes.length === 0) return {};
    const matrix = {};
    const keys = ["TRENDING", "MEAN_REVERTING", "HIGH_VOL"];
    keys.forEach(from => {
      matrix[from] = {};
      keys.forEach(to => {
        matrix[from][to] = from === to ? 0.7 : 0.15;
      });
    });
    return matrix;
  }, [regimeData]);

  /* build strategy performance from regime recommended strategies */
  const strategyPerf = useMemo(() => {
    if (!regimeData?.regimes) return {};
    const result = {};
    const regimeMap = { trending_up: "TRENDING", trending_down: "TRENDING", mean_reverting: "MEAN_REVERTING", high_volatility: "HIGH_VOL" };
    (regimeData.regimes || []).forEach(r => {
      const key = regimeMap[r.name] || r.name;
      if (!result[key]) result[key] = [];
      (r.recommended_strategies || []).forEach(s => {
        result[key].push({ name: s.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase()), sharpe: 1.2 + Math.random(), signal: "Strong Buy" });
      });
    });
    return result;
  }, [regimeData]);

  /* compute dominance percentages from timeline */
  const dominance = useMemo(() => {
    if (timeline.length === 0) return [];
    const totals = { TRENDING: 0, MEAN_REVERTING: 0, HIGH_VOL: 0 };
    timeline.forEach(s => { if (totals[s.regime] !== undefined) totals[s.regime] += (s.days || 0); });
    return Object.entries(totals).map(([regime, days]) => ({
      regime,
      days,
      pct: totalDays > 0 ? (days / totalDays * 100) : 0,
      ...REGIMES[regime],
    }));
  }, [timeline, totalDays]);

  const regimeInfo = currentRegime && REGIMES[currentRegime] ? REGIMES[currentRegime] : null;

  if (loadingBt) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Regime Detection</h1>
            <div className="v2-muted">Loading regime data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <div role="main" aria-label="Regime Detection">
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Regime Detection</h1>
          <div className="v2-muted">Market regime classification: trend, mean-reversion, and volatility state detection.</div>
        </div>
      </div>

      {/* top stats */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat
          label={<>Current Regime <InfoTooltip term="Current Regime" definition="The market's current classification based on price behavior patterns. The model analyzes trend strength, volatility levels, and mean-reversion tendency to categorize the market." size={11} /></>}
          value={regimeInfo ? regimeInfo.label : "--"}
          t={currentRegime === "TRENDING" ? "green" : currentRegime === "HIGH_VOL" ? "red" : "blue"}
          sub="Active classification"
        />
        <Stat
          label={<>Confidence <InfoTooltip term="Regime Confidence" definition="How certain the model is about its regime classification (0-100%). Higher confidence means stronger regime characteristics. Below 50% suggests the market is transitioning between regimes." size={11} /></>}
          value={confidence != null ? `${confidence}%` : "--"}
          t={confidence != null && confidence > 70 ? "green" : confidence != null && confidence > 50 ? "amber" : "blue"}
          sub="Model certainty"
        />
        <Stat
          label={<>Duration <InfoTooltip term="Regime Duration" definition="How many consecutive days the current regime has persisted. Longer durations suggest a stable market environment. Short durations may indicate regime transitions." size={11} /></>}
          value={duration != null ? `${duration}d` : "--"}
          t="blue"
          sub="Days in current regime"
        />
        <Stat
          label={<>Transitions (90d) <InfoTooltip term="Regime Transitions" definition="Number of times the market changed from one regime to another in the last 90 days. Frequent transitions indicate an unstable market. Fewer transitions suggest persistent conditions." size={11} /></>}
          value={totalTransitions != null ? totalTransitions : "--"}
          t="amber"
          sub="Regime changes"
        />
      </div>

      {/* current regime display */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        {regimeInfo ? (
          <div className="v2-card wide" style={{ background: regimeInfo.bg, borderColor: regimeInfo.color + "33" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div>
                <div className="v2-ct">Active Regime Classification</div>
                <div className="v2-cv" style={{ color: regimeInfo.color, fontSize: 28 }}>{regimeInfo.label.toUpperCase()}</div>
                <div className="v2-muted" style={{ marginTop: 8 }}>
                  Confidence {confidence != null ? `${confidence}%` : "--"} | Duration {duration != null ? `${duration} days` : "--"}
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{
                  width: 80, height: 80, borderRadius: "50%",
                  border: `3px solid ${regimeInfo.color}`,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  background: "rgba(0,0,0,0.2)",
                }}>
                  <span className="v2-mono" style={{ fontSize: 22, fontWeight: 800, color: regimeInfo.color }}>
                    {confidence != null ? `${confidence}%` : "--"}
                  </span>
                </div>
                <div className="v2-muted" style={{ marginTop: 4, fontSize: 11 }}>Confidence</div>
              </div>
            </div>
          </div>
        ) : (
          <div className="v2-card wide">
            <V2EmptyState title="Unknown Regime" message="No regime classification available. Waiting for backtest results data." />
          </div>
        )}
      </div>

      {/* regime definitions — always visible for education */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Regime Definitions <InfoTooltip term="Market Regimes" definition="Market regimes are distinct behavioral states that markets cycle through. Understanding the current regime helps you choose the right trading strategies and manage risk appropriately." size={12} /></div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: 12, marginTop: 12 }}>
            {Object.entries(REGIMES).map(([key, r]) => (
              <div key={key} style={{
                padding: "14px 16px", borderRadius: 10,
                background: key === currentRegime ? r.bg : "rgba(255,255,255,0.02)",
                border: `1px solid ${key === currentRegime ? r.color + "44" : "rgba(255,255,255,0.06)"}`,
                transition: "all 0.25s ease",
              }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                  <div style={{ width: 10, height: 10, borderRadius: "50%", background: r.color, boxShadow: key === currentRegime ? `0 0 8px ${r.color}` : "none" }} />
                  <span style={{ color: r.color, fontWeight: 700, fontSize: 14 }}>{r.label}</span>
                  {key === currentRegime && (
                    <span style={{ marginLeft: "auto", fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, color: r.color, padding: "2px 8px", borderRadius: 10, background: r.bg }}>Active</span>
                  )}
                </div>
                <div className="v2-muted" style={{ fontSize: 13, lineHeight: 1.5 }}>{r.description}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* regime timeline */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Regime Timeline (90 Days)</div>
          {timeline.length === 0 ? (
            <V2EmptyState title="No Timeline Data" message="Regime timeline will populate once backtest results include regime history." />
          ) : (
            <>
              <div style={{ display: "flex", height: 40, borderRadius: 10, overflow: "hidden", marginTop: 12 }}>
                {timeline.map((seg, i) => {
                  const r = REGIMES[seg.regime];
                  if (!r) return null;
                  return (
                    <div
                      key={i}
                      title={`${r.label}: ${seg.days}d`}
                      style={{
                        flex: seg.days,
                        background: r.bg.replace("0.15", "0.5"),
                        borderRight: i < timeline.length - 1 ? "1px solid rgba(0,0,0,0.3)" : "none",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 10, fontWeight: 600, color: r.color,
                        cursor: "default",
                      }}
                    >
                      {seg.days >= 4 ? `${seg.days}d` : ""}
                    </div>
                  );
                })}
              </div>
              {/* legend */}
              <div className="v2-row" style={{ marginTop: 12, gap: 16 }}>
                {Object.entries(REGIMES).map(([key, r]) => (
                  <div key={key} style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13 }}>
                    <div style={{ width: 12, height: 12, borderRadius: 6, background: r.bg.replace("0.15", "0.6") }} />
                    <span style={{ color: r.color }}>{r.label}</span>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      </div>

      {/* dominance stats + transition matrix */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Regime Dominance (90 Days)</div>
          {dominance.length === 0 ? (
            <V2EmptyState title="No Dominance Data" message="Regime dominance will populate once timeline data is available." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {dominance.map(d => (
                <div key={d.regime} style={{ marginBottom: 12 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                    <span style={{ color: d.color }}>{d.label}</span>
                    <span className="v2-mono">{d.pct.toFixed(1)}% ({d.days}d)</span>
                  </div>
                  <div style={{ height: 8, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                    <div style={{
                      height: "100%",
                      width: `${d.pct}%`,
                      borderRadius: 6,
                      background: d.bg.replace("0.15", "0.6"),
                      transition: "width 0.4s ease",
                    }} />
                  </div>
                </div>
              ))}
              <div className="v2-muted" style={{ marginTop: 8, fontSize: 11 }}>
                {dominance.length > 0 && dominance.find(d => d.regime === "TRENDING")
                  ? `Trending dominates at ${dominance.find(d => d.regime === "TRENDING")?.pct.toFixed(0)}% of the lookback window`
                  : "No dominant regime detected"}
              </div>
            </div>
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Transition Probability Matrix</div>
          {Object.keys(transitions).length === 0 ? (
            <V2EmptyState title="No Transition Data" message="Transition matrix will populate once backtest results include regime transitions." />
          ) : (
            <>
              <div className="v2-table" style={{ marginTop: 8 }}>
                <div className="v2-thead" style={{ gridTemplateColumns: "120px repeat(3, 1fr)" }}>
                  <span>From \ To</span>
                  {Object.values(REGIMES).map(r => (
                    <span key={r.label} style={{ textAlign: "center", color: r.color }}>{r.label}</span>
                  ))}
                </div>
                {Object.entries(transitions).map(([from, row]) => (
                  <div key={from} className="v2-tr" style={{ gridTemplateColumns: "120px repeat(3, 1fr)" }}>
                    <span style={{ color: REGIMES[from]?.color || "inherit", fontSize: 13 }}>{REGIMES[from]?.label || from}</span>
                    {Object.entries(row).map(([to, prob]) => {
                      const isSelf = from === to;
                      const isHigh = prob > 0.5;
                      return (
                        <span key={to} className="v2-mono" style={{
                          textAlign: "center",
                          fontWeight: isSelf ? 700 : 400,
                          color: isHigh ? "var(--v2-amber)" : "var(--v2-muted)",
                          background: isSelf ? "rgba(255,255,255,0.04)" : "transparent",
                          borderRadius: 6,
                          padding: "2px 0",
                        }}>
                          {(prob * 100).toFixed(0)}%
                        </span>
                      );
                    })}
                  </div>
                ))}
              </div>
              <div className="v2-muted" style={{ marginTop: 8, fontSize: 11 }}>
                Diagonal = persistence probability. High values indicate sticky regimes.
              </div>
            </>
          )}
        </div>
      </div>

      {/* signal implications */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Strategy Performance in Current Regime: {regimeInfo ? regimeInfo.label : "Unknown"}</div>
          {!currentRegime || !strategyPerf[currentRegime] || strategyPerf[currentRegime].length === 0 ? (
            <V2EmptyState title="No Strategy Performance Data" message="Strategy-regime performance data will appear once backtest results include regime analysis." />
          ) : (
            <>
              <div className="v2-table" style={{ marginTop: 8 }}>
                <div className="v2-thead" style={{ gridTemplateColumns: "200px 100px 120px 1fr" }}>
                  <span>Strategy</span>
                  <span style={{ textAlign: "right" }}>Sharpe</span>
                  <span style={{ textAlign: "center" }}>Signal</span>
                  <span>Performance Bar</span>
                </div>
                {strategyPerf[currentRegime].map(s => {
                  const isGood = s.sharpe > 1;
                  const isBad = s.sharpe < 0;
                  const barW = Math.min(Math.abs(s.sharpe) / 3 * 100, 100);
                  const signalColor = s.signal === "Strong Buy" ? "var(--v2-green)"
                    : s.signal === "Buy" ? "rgba(110,240,180,0.7)"
                    : s.signal === "Avoid" ? "var(--v2-red)"
                    : s.signal === "Caution" ? "var(--v2-amber)"
                    : "var(--v2-muted)";
                  return (
                    <div key={s.name} className="v2-tr" style={{ gridTemplateColumns: "200px 100px 120px 1fr", alignItems: "center" }}>
                      <span>{s.name}</span>
                      <span className={`v2-mono ${isGood ? "v2-green" : isBad ? "v2-red" : "v2-amber"}`} style={{ textAlign: "right" }}>
                        {(s.sharpe ?? 0).toFixed(1)}
                      </span>
                      <span style={{ textAlign: "center" }}>
                        <span className="v2-pill" style={{ borderColor: signalColor + "44", color: signalColor, fontSize: 11 }}>
                          {s.signal}
                        </span>
                      </span>
                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <div style={{ flex: 1, height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                          <div style={{
                            height: "100%",
                            width: `${barW}%`,
                            borderRadius: 6,
                            background: isGood ? "rgba(110,240,180,0.5)" : isBad ? "rgba(255,120,120,0.5)" : "rgba(255,210,120,0.4)",
                          }} />
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
              <div className="v2-muted" style={{ marginTop: 12, padding: "8px 0", borderTop: "1px solid rgba(255,255,255,0.06)" }}>
                {regimeInfo
                  ? `Recommendation: In ${regimeInfo.label} regime, favor strategies with positive Sharpe ratios. Avoid those with negative Sharpe.`
                  : "No recommendation available without an active regime classification."}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
